const queries = ["AI automation creators", "YouTube automation tutorial creators", "Instagram AI workflow creators"];
const referenceCreators = ["Nate Zerk"];
return queries.map((query) => ({ json: { query, referenceCreators } }));

const toHex = (value) => (value >>> 0).toString(16).padStart(8, '0');
const makeDeterministicUuid = (input) => {
  const text = String(input || 'unknown').toLowerCase().trim();
  let h1 = 2166136261;
  let h2 = 2166136261;
  let h3 = 2166136261;
  let h4 = 2166136261;

  for (let i = 0; i < text.length; i++) {
    const c = text.charCodeAt(i);
    h1 = Math.imul(h1 ^ c, 16777619) >>> 0;
    h2 = Math.imul(h2 ^ (c + 31), 16777619) >>> 0;
    h3 = Math.imul(h3 ^ (c + 131), 16777619) >>> 0;
    h4 = Math.imul(h4 ^ (c + 521), 16777619) >>> 0;
  }

  const hex = `${toHex(h1)}${toHex(h2)}${toHex(h3)}${toHex(h4)}`.slice(0, 32);
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
};

const tavilyItems = $input.all();
const queryItems = $('Build Search Queries').all();
const out = [];

tavilyItems.forEach((item, idx) => {
  const sourceQuery = (queryItems[idx] && queryItems[idx].json.query) || 'unknown';
  const results = item.json.results || [];
  results.forEach((result) => {
    const creatorName = result.title || result.name || result.url;
    out.push({
      json: {
        creator_id: makeDeterministicUuid(creatorName),
        creator_name: creatorName,
        profile_url: result.url,
        source_query: sourceQuery,
        source_snippet: result.content || result.snippet || '',
        relevance_score: result.score || 0,
        platform: 'youtube'
      }
    });
  });
});

return out;

const items = $input.all();
return items.map((item) => {
  const url = String(item.json.profile_url || '');
  let channelId = null;
  let handle = null;
  let isYouTube = false;

  try {
    const hostname = new URL(url).hostname.toLowerCase();
    isYouTube = hostname === 'youtube.com' || hostname.endsWith('.youtube.com') || hostname === 'youtu.be';
  } catch (e) {
    isYouTube = false;
  }

  if (isYouTube) {
    const idMatch = url.match(/\/channel\/(UC[\w-]{10,})/i);
    if (idMatch) channelId = idMatch[1];
    if (!channelId) {
      const handleMatch = url.match(/\/@([\w.\-]+)/);
      if (handleMatch) handle = handleMatch[1];
    }
    if (!channelId && !handle) {
      const legacyMatch = url.match(/\/(?:c|user)\/([\w.\-]+)/i);
      if (legacyMatch) handle = legacyMatch[1];
    }
  }

  return { json: { ...item.json, channelId, handle, resolvable: Boolean(channelId || handle) } };
});

const items = $input.all();
const sources = $('YT Resolvable Filter').all();
return items.map((item, i) => {
  const source = sources[i]?.json || {};
  const channel = item.json?.items?.[0];
  const uploadsPlaylistId = channel?.contentDetails?.relatedPlaylists?.uploads || null;
  return { json: { ...source, resolved_channel_id: channel?.id || source.channelId || null, uploads_playlist_id: uploadsPlaylistId } };
});

const items = $input.all();
const sources = $('YT Has Playlist Filter').all();
return items.map((item, i) => {
  const source = sources[i]?.json || {};
  const videoIds = (item.json?.items || []).map((p) => p.contentDetails?.videoId).filter(Boolean);
  return { json: { ...source, video_ids: videoIds.join(',') } };
});

const items = $input.all();
const sources = $('YT Has VideoIds Filter').all();
return items.map((item, i) => {
  const source = sources[i]?.json || {};
  return { json: { ...source, items: item.json?.items || [] } };
});

const parseIsoDuration = (iso) => {
  const match = /^PT(?:(\d+)H)?(?:(\d+)M)?(?:(\d+)S)?$/.exec(iso || '');
  if (!match) return null;
  const [, h, m, s] = match;
  return (Number(h || 0) * 3600) + (Number(m || 0) * 60) + Number(s || 0);
};

const toHex = (value) => (value >>> 0).toString(16).padStart(8, '0');
const makeDeterministicUuid = (input) => {
  const text = String(input || 'unknown').toLowerCase().trim();
  let h1 = 2166136261;
  let h2 = 2166136261;
  let h3 = 2166136261;
  let h4 = 2166136261;

  for (let i = 0; i < text.length; i++) {
    const c = text.charCodeAt(i);
    h1 = Math.imul(h1 ^ c, 16777619) >>> 0;
    h2 = Math.imul(h2 ^ (c + 31), 16777619) >>> 0;
    h3 = Math.imul(h3 ^ (c + 131), 16777619) >>> 0;
    h4 = Math.imul(h4 ^ (c + 521), 16777619) >>> 0;
  }

  const hex = `${toHex(h1)}${toHex(h2)}${toHex(h3)}${toHex(h4)}`.slice(0, 32);
  return `${hex.slice(0, 8)}-${hex.slice(8, 12)}-${hex.slice(12, 16)}-${hex.slice(16, 20)}-${hex.slice(20, 32)}`;
};

const creators = $input.all();
return creators.flatMap((item) => {
  const videos = item.json.items || [];
  return videos.map((video) => {
    const viewCount = Number(video.statistics?.viewCount || 0);
    const likeCount = Number(video.statistics?.likeCount || 0);
    const commentCount = Number(video.statistics?.commentCount || 0);
    const engagementRate = viewCount > 0 ? Number(((likeCount + commentCount) / viewCount).toFixed(4)) : 0;
    const creatorName = item.json.creator_name || video.snippet?.channelTitle || String(video.snippet?.channelId || 'unknown_creator');

    return {
      json: {
        creator_id: item.json.creator_id || makeDeterministicUuid(creatorName),
        creator_name: creatorName,
        profile_url: item.json.profile_url,
        platform_video_id: video.id?.videoId || video.id,
        title: video.snippet?.title || '',
        description: video.snippet?.description || '',
        published_at: video.snippet?.publishedAt || null,
        duration_seconds: parseIsoDuration(video.contentDetails?.duration),
        view_count: viewCount,
        like_count: likeCount,
        comment_count: commentCount,
        engagement_rate: engagementRate,
        thumbnail_url: video.snippet?.thumbnails?.high?.url || video.snippet?.thumbnails?.default?.url || null,
        raw_payload: video,
        hashtags: [],
        format_tags: []
      }
    };
  });
});

const records = $input.all();
const batchId = `batch-${new Date().toISOString().replace(/[:.]/g, '-')}`;
return records.map((item) => ({
  json: {
    ...item.json,
    batch_id: batchId,
    analysis_version: 'stage3-v1',
    analysis_status: 'pending',
    analysis_payload: {
      analysis_version: 'stage3-v1',
      batch_id: batchId,
      creator_name: item.json.creator_name,
      platform: 'youtube',
      platform_video_id: item.json.platform_video_id,
      title: item.json.title,
      description: item.json.description,
      published_at: item.json.published_at,
      duration_seconds: item.json.duration_seconds,
      view_count: item.json.view_count,
      like_count: item.json.like_count,
      comment_count: item.json.comment_count,
      hashtags: item.json.hashtags || [],
      engagement_rate: item.json.engagement_rate,
      format_tags: item.json.format_tags || []
    },
    topic_category: null,
    primary_format: null,
    engagement_tier: null,
    analysis_confidence: null,
    pattern_summary: {}
  }
}));

const response = $input.first().json;
const source = $('Stage 3 Contract Builder').first().json;
const text = response.content?.[0]?.text || response.output_text || response.output?.[0]?.content?.[0]?.text || '';
let parsed = {};
try {
  parsed = typeof text === 'string' && text.trim() ? JSON.parse(text) : response;
} catch (error) {
  parsed = response;
}
return [{
  json: {
    ...source,
    ...parsed,
    batch_id: parsed.batch_id || source.batch_id,
    platform_video_id: parsed.platform_video_id || source.platform_video_id,
    analysis_status: 'analyzed',
    analysis_payload: parsed
  }
}];

const source = $input.first().json || {};
return [{
  json: {
    ...source,
    analysis_status: 'deferred_session_limit',
    analysis_payload: {
      deferred_reason: 'model_access_unavailable',
      deferred_at: new Date().toISOString(),
      provider_requested: 'deferred'
    },
    topic_category: source.topic_category || null,
    primary_format: source.primary_format || null,
    engagement_tier: source.engagement_tier || null,
    analysis_confidence: source.analysis_confidence || null,
    pattern_summary: source.pattern_summary || {}
  }
}];

const source = $input.first().json || {};
const analysis = source.analysis_payload || {};
const summary = source.pattern_summary || {};
const confidence = typeof source.analysis_confidence === 'number' ? source.analysis_confidence : null;
const reasoningParts = [
  analysis.reasoning || analysis.why_this_format || '',
  summary.caption_structure || '',
  summary.hashtag_cluster || ''
].filter(Boolean);

return [{
  json: {
    ...source,
    playbook_status: 'pending',
    playbook_page_id: null,
    playbook_synced_at: null,
    playbook_payload: {
      batch_id: source.batch_id || null,
      platform_video_id: source.platform_video_id || null,
      creator_name: source.creator_name || analysis.creator_name || null,
      topic_type: source.topic_category || analysis.topic_category || 'uncategorized',
      recommended_format: source.primary_format || analysis.primary_format || 'unknown',
      engagement_tier: source.engagement_tier || analysis.engagement_tier || 'unknown',
      confidence,
      reasoning: reasoningParts.join(' | ').slice(0, 1800),
      example_reference: source.title || analysis.title || null,
      source_url: source.profile_url || null,
      published_at: source.published_at || null,
      evidence: analysis.evidence || summary || {}
    }
  }
}];

const source = $input.first().json || {};
return [{
  json: {
    ...source,
    playbook_status: 'skipped_not_analyzed',
    playbook_page_id: null,
    playbook_synced_at: null,
    playbook_payload: {
      ...(source.playbook_payload || {}),
      skip_reason: `analysis_status_${source.analysis_status || 'unknown'}`
    }
  }
}];

const source = $('Stage 4 Playbook Mapper').first().json || {};
const response = $input.first().json || {};
return [{
  json: {
    ...source,
    playbook_status: 'synced',
    playbook_page_id: response.id || null,
    playbook_synced_at: new Date().toISOString(),
    playbook_payload: {
      ...(source.playbook_payload || {}),
      notion_response_id: response.id || null,
      notion_url: response.url || null
    }
  }
}];

const source = $input.first().json || {};
const eligible = source.analysis_status === 'analyzed' && source.playbook_status === 'synced';
const score = eligible && typeof source.analysis_confidence === 'number'
  ? Number(source.analysis_confidence.toFixed(4))
  : null;

return [{
  json: {
    ...source,
    feedback_status: 'pending_first_party_data',
    feedback_score: score,
    feedback_payload: {
      batch_id: source.batch_id || null,
      platform_video_id: source.platform_video_id || null,
      stage4_status: source.playbook_status || 'unknown',
      analysis_status: source.analysis_status || 'unknown',
      scaffold_mode: 'deferred_until_first_party_metrics',
      eligible_for_blend: Boolean(eligible),
      next_action: 'ingest_first_party_posts'
    }
  }
}];

const items = $input.all();
const first = items[0]?.json || {};
return [{
  json: {
    batch_id: first.batch_id || null,
    status: 'ingested',
    provider: 'claude',
    run_finished_at: new Date().toISOString(),
    video_count: items.length
  }
}];

return $input.all().map((item) => {
  const json = item.json;
  const ytChannelQuery = json.channelId
    ? { part: 'contentDetails,snippet', id: json.channelId }
    : { part: 'contentDetails,snippet', forHandle: json.handle };
  return { json: { ...json, ytChannelQuery } };
});
